/* ?????????????????????????????????????????
   HOOK: ?⑤씪???곹깭 媛먯?
????????????????????????????????????????? */
function useOnlineStatus() {
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  useEffect(() => {
    const on = () => setIsOnline(true);
    const off = () => setIsOnline(false);
    window.addEventListener("online", on);
    window.addEventListener("offline", off);
    return () => {
      window.removeEventListener("online", on);
      window.removeEventListener("offline", off);
    };
  }, []);
  return isOnline;
}

/* ?????????????????????????????????????????
   HOOK: PWA ?ㅼ튂 ?꾨＼?꾪듃
????????????????????????????????????????? */
interface BeforeInstallPromptEvent extends Event {
  prompt(): Promise<void>;
  userChoice: Promise<{ outcome: "accepted" | "dismissed" }>;
}

function useInstallPrompt() {
  const [deferredPrompt, setDeferredPrompt] = useState<BeforeInstallPromptEvent | null>(null);
  const [showBanner, setShowBanner] = useState(false);
  const [isIOS, setIsIOS] = useState(false);

  useEffect(() => {
    const dismissed = safeStorage.get("hg_install_dismissed");
    if (dismissed) return;
    const standalone = window.matchMedia("(display-mode: standalone)").matches
      || (window.navigator as any).standalone === true;
    if (standalone) return; // ?대? ?ㅼ튂??

    const ios = /iPad|iPhone|iPod/.test(navigator.userAgent) && !(window as any).MSStream;
    if (ios) {
      setIsIOS(true);
      setShowBanner(true);
      return;
    }
    const handler = (e: Event) => {
      e.preventDefault();
      setDeferredPrompt(e as BeforeInstallPromptEvent);
      setShowBanner(true);
    };
    window.addEventListener("beforeinstallprompt", handler);
    return () => window.removeEventListener("beforeinstallprompt", handler);
  }, []);

  const handleInstall = async () => {
    if (isIOS) return; // iOS??踰꾪듉 ?대┃ ?놁쓬 ???덈궡留?
    if (!deferredPrompt) return;
    await deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    if (outcome === "accepted") {
      setShowBanner(false);
      setDeferredPrompt(null);
    }
  };

  const handleDismiss = () => {
    setShowBanner(false);
    safeStorage.set("hg_install_dismissed", "1")
  };

  return { showBanner, handleInstall, handleDismiss, isIOS };
}

/* ?????????????????????????????????????????
   UTIL: 濡쒖뺄 ?뚮┝ ?ㅼ?以꾨쭅
????????????????????????????????????????? */
async function scheduleReminder(title: string, daysLater: number) {
  if (!("Notification" in window)) {
    alert("??釉뚮씪?곗????뚮┝??吏?먰븯吏 ?딆뒿?덈떎.");
    return;
  }
  if (Notification.permission !== "granted") {
    const perm = await Notification.requestPermission();
    if (perm !== "granted") return;
  }
  const ms = daysLater * 24 * 60 * 60 * 1000;
  const reminders = safeStorage.getJSON("hg_reminders", []);
  reminders.push({ title, fireAt: Date.now() + ms });
  safeStorage.setJSON("hg_reminders", reminders)
  new Notification("HebronGuide ?뚮┝ ?ㅼ젙", {
    body: `"${title}" ??${daysLater}?????뚮┝??諛쏆뒿?덈떎`,
    icon: "/icon-192.png",
  });
}

