// ?붾뱶而??쒖쫵(6/1~7/26) ?쒖젙 ???대떦 ?꾩떆 寃쎄린??援먰넻 ?뺣낫 1?쒖쐞 ?먮룞 ?쎌엯
// isWorldCupActive(slug): 湲곗〈 WORLD_CUP_2026 ?곸닔 ?쒖슜 (?뚯씪 ?섎떒???뺤쓽??
// ?쒖쫵 醫낅즺 ???먮룞 蹂듭썝 (肄붾뱶 ?섏젙 ?놁쓬)

function withWorldCupTransit(slug: CitySlug, items: Top5Item[]): Top5Item[] {
  // NOTE: isWorldCupActive(slug)?????뚯씪 ?섎떒 ~2551踰덉㎏ ?쇱씤???뺤쓽??  // 鍮뚮뱶 ???몄씠?ㅽ똿?쇰줈 ?뺤긽 李몄“??(function declaration)

  if (!isWorldCupActive(slug)) return items;
  const wcItem = WC_TRANSIT[slug];
  if (!wcItem) return items;
  return [wcItem, ...items.slice(0, 4).map((x, i) => ({ ...x, rank: i + 2 }))];
}

