const COMM_KEY = "hg_community_v2";

// ?? 而ㅻ??덊떚 ?곗씠???먮룞 ?섏쭛 (Supabase REST API 吏곸젒 ??? ??

const SUPA_REST = `https://${projectId}.supabase.co/rest/v1/community_items`;


function postToServer(item: any) {
  try {
    fetch(SUPA_REST, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "apikey":        publicAnonKey,
        "Authorization": `Bearer ${publicAnonKey}`,
        "Prefer":        "return=minimal",
      },
      body: JSON.stringify({
        category:    item.category,
        city_slug:   item.citySlug,
        name:        item.name,
        contact:     item.contact,
        description: item.desc,
        website:     item.website || "",
      }),
    }).catch(() => {}); // ?ㅽ뙣?대룄 ???숈옉???곹뼢 ?놁쓬
  } catch {}
}
function readCommunity(): any[] {
  return safeStorage.getJSON(COMM_KEY, []);
}
function writeCommunity(items: any[]) {
  safeStorage.setJSON(COMM_KEY, items.slice(0, 200));
}
function addCommunityItem(item: any) {
  const items = readCommunity();
  items.unshift({ ...item, id: Date.now().toString(), addedAt: new Date().toISOString().slice(0, 10) });
  writeCommunity(items);
}
function getCommunityByCategory(citySlug: string, category: string): any[] {
  return readCommunity().filter(i => i.citySlug === citySlug && i.category === category);
}

// ?? ?먮룞 踰덉뿭 (MyMemory 臾대즺 API) ????????????????????????????
async function autoTranslate(text: string, from: string, to: string): Promise<string> {
  if (!text.trim() || from === to) return text;
  try {
    const res = await fetch(
      `https://api.mymemory.translated.net/get?q=${encodeURIComponent(text.slice(0,400))}&langpair=${from}|${to}`
    );
    const data = await res.json();
    return data?.responseData?.translatedText ?? text;
  } catch { return text; }
}

async function translateAll(text: string, srcLang: string): Promise<{ko:string;en:string;es:string}> {
  if (!text.trim()) return { ko:"", en:"", es:"" };
  const [ko, en, es] = await Promise.all([
    srcLang === "ko" ? text : autoTranslate(text, srcLang, "ko"),
    srcLang === "en" ? text : autoTranslate(text, srcLang, "en"),
    srcLang === "es" ? text : autoTranslate(text, srcLang, "es"),
  ]);
  return { ko, en, es };
}

