// 吏곸젒 ?섎뱶肄붾뵫 湲덉?`: `${x}濡? ?? ?? `${x}${roJosa(x)}` ??//
// ?먮퀎 湲곗?: 留덉?留??쒓? ?뚯젅??醫낆꽦(諛쏆묠) ?좊Т
//   諛쏆묠 ?놁쓬 / 諛쏆묠 ??"濡?, "媛", "瑜?, "??",  "?"
//   洹???諛쏆묠          ??"?쇰줈", "??",  "??",  "?", "怨?
//   鍮꾪븳湲(?곸뼱 ??     ??諛쏆묠 ?놁쓬 痍④툒


function _jongseong(s: string): number {
  const code = s.trimEnd().charCodeAt(s.trimEnd().length - 1);
  if (code >= 0xAC00 && code <= 0xD7A3) return (code - 0xAC00) % 28;
  return 0; // 鍮꾪븳湲 ??諛쏆묠 ?놁쓬 痍④툒
}
/** "濡? vs "?쇰줈" */
function roJosa(s: string): string {
  const j = _jongseong(s);
  return (j === 0 || j === 8) ? "濡?" : "?쇰줈";
}
/** "?? vs "媛" (二쇨꺽 議곗궗) */
function iGaJosa(s: string): string {
  return _jongseong(s) !== 0 ? "????" : "媛";
}
/** "?? vs "瑜? (紐⑹쟻寃?議곗궗) */
function eulReulJosa(s: string): string {
  return _jongseong(s) !== 0 ? "????" : "瑜?";
}
/** "?" vs "?? (蹂댁“?? */
function eunNeunJosa(s: string): string {
  return _jongseong(s) !== 0 ? "?" : "??";
}
/** "怨? vs "?" (?묒냽 議곗궗) */
function waGwaJosa(s: string): string {
  return _jongseong(s) !== 0 ? "怨?" : "?";
}
