// TOP5Item ??PlaceCard ?щ㎎ 蹂??(?꾩떆蹂?留쏆쭛 ??fallback??

function top5ToPlaceCards(items: Top5Item[], lang: string) {
  return items.map(item => ({
    emoji: item.emoji,
    name: `${item.nameKo}${item.rating ? ` ??Yelp ${item.rating}` : ""}`,
    nameEn: item.nameEn,
    desc: lang === "ko"
      ? [
          "??寃利앸맖",
          item.address ? `?뱧 ${item.address}` : "",
          item.phone ? `?뱸 ${item.phone}` : "",
          item.hours ? `??${item.hours}` : "",
          item.why,
          item.tip ? `?뮕 ${item.tip}` : "",
          item.website ? `?뵕 ${item.website}` : "",
        ].filter(Boolean).join("\n")
      : [
          "??Verified",
          item.address ? `?뱧 ${item.address}` : "",
          item.phone ? `?뱸 ${item.phone}` : "",
          item.hours ? `??${item.hours}` : "",
          item.why,
          item.tip ? `?뮕 ${item.tip}` : "",
          item.website ? `?뵕 ${item.website}` : "",
        ].filter(Boolean).join("\n"),
    tags: ["寃利앸맖"],
  }));
}

