/* ?????????????????????????????????????????
   ?ㅻ쭏??怨듭쑀 紐⑤떖 ????퀎 留욎땄 硫붿떆吏 + 硫??SNS
????????????????????????????????????????? */

// ??퀎 怨듭쑀 肄섑뀗痢????꾩떆紐??숈쟻 ?앹꽦 (?쒖븷???湲곗? ?쒗뵆由우쑝濡?紐⑤뱺 ?꾩떆???곸슜)
// ?쒓뎅??議곗궗 ?먮룞 ?좏깮 ??諛쏆묠 ?덉쑝硫?"?쇰줈", ?놁쑝硫?"濡?

function withRo(word: string): string {
  const last = word[word.length - 1];
  const code = last?.charCodeAt(0) ?? 0;
  if (code >= 0xAC00 && code <= 0xD7A3) {
    const jong = (code - 0xAC00) % 28; // 醫낆꽦 ?몃뜳??
    return word + (jong !== 0 ? "?쇰줈" : "濡?");
  }
  return word + "濡?"; // ?곷Ц쨌湲고?"}
}


